import vex

# pip install autogen vex-sdk
vex_client = vex.Client(api_key="your-vex-api-key")

@vex_client.guardrail(
    checks=[
        "response-accuracy",
        "pii-filtering",
        "tone-consistency:professional",
        "policy-compliance:support",
        "escalation-trigger:refund_request"
    ]
)
def vex_filtered_reply(sender, recipient, message):
    verified = vex_client.verify(
        message,
        context={"domain": "customer_support", "risk_profile": "high"}
    )
    if verified:
        return message
    else:
        return "Escalating to human agent due to verification failure."

# Register with all agents
for agent in [rag_agent, crm_agent, policy_agent, supervisor]:
    agent.register_reply([GroupChatManager], reply_func=vex_filtered_reply)

@vex_client.guardrail(name="loop-detection", checks=["conversation-loop"])
def detect_loops(sender, recipient, message, chat_history):
    if len([m for m in chat_history[-10:] if "order status" in m]) > 3:
        return "LOOP_DETECTED: Force escalate"
    return message

manager.register_reply(supervisor, reply_func=detect_loops)

@vex_client.guardrail(checks=["pii-filtering"])
def safe_crm_call(func_name, *args):
    redacted_args = vex_client.redact(str(args))
    result = globals()[func_name](*args)
    return vex_client.scrub_pii(result)

# Wrap CRM tools
safe_lookup = lambda order_id: safe_crm_call('lookup_order', order_id)
crm_agent.register_for_llm(name="safe_lookup")(safe_lookup)
crm_agent.register_for_llm(name="safe_create_ticket")(lambda s,e: safe_crm_call('create_ticket', s, e))
